# Multimodal AI: Image analysis and description pipeline
import base64
import json
from pathlib import Path
from typing import List, Optional, Dict, Any
from dataclasses import dataclass
import time


@dataclass
class ImageAnalysis:
    image_path: str
    description: str
    objects_detected: List[str]
    text_extracted: Optional[str]
    colors_dominant: List[str]
    confidence: float
    processing_time_ms: float
    model_used: str


class MultimodalAnalyzer:
    """Analyze images using multimodal AI models."""

    def __init__(self, provider: str = "openai"):
        self.provider = provider
        self._setup_client()

    def _setup_client(self):
        """Initialize the appropriate client."""
        if self.provider == "openai":
            from openai import OpenAI
            self.client = OpenAI()
        elif self.provider == "anthropic":
            import anthropic
            self.client = anthropic.Anthropic()
        else:
            raise ValueError(f"Unknown provider: {self.provider}")

    def encode_image(self, image_path: str) -> str:
        """Encode image to base64."""
        with open(image_path, "rb") as f:
            return base64.b64encode(f.read()).decode("utf-8")

    def analyze_image(
        self,
        image_path: str,
        prompt: str = "Analyze this image in detail",
        detail: str = "high",
    ) -> ImageAnalysis:
        """Analyze a single image with multimodal AI."""
        start = time.perf_counter()

        if self.provider == "openai":
            result = self._analyze_openai(image_path, prompt, detail)
        elif self.provider == "anthropic":
            result = self._analyze_anthropic(image_path, prompt)

        processing_time = (time.perf_counter() - start) * 1000

        return ImageAnalysis(
            image_path=image_path,
            description=result["description"],
            objects_detected=result.get("objects", []),
            text_extracted=result.get("text"),
            colors_dominant=result.get("colors", []),
            confidence=result.get("confidence", 0.0),
            processing_time_ms=processing_time,
            model_used=result.get("model", "unknown"),
        )

    def _analyze_openai(
        self, image_path: str, prompt: str, detail: str
    ) -> Dict[str, Any]:
        """Analyze using OpenAI GPT-4o."""
        base64_image = self.encode_image(image_path)
        suffix = Path(image_path).suffix.lower()
        mime_type = {".jpg": "image/jpeg", ".jpeg": "image/jpeg", ".png": "image/png"}.get(
            suffix, "image/jpeg"
        )

        response = self.client.chat.completions.create(
            model="gpt-4o",
            messages=[
                {
                    "role": "system",
                    "content": (
                        "Analyze images and provide detailed descriptions. "
                        "Respond in JSON with keys: description, objects (list), "
                        "text (extracted text), colors (list), confidence (0-1)."
                    ),
                },
                {
                    "role": "user",
                    "content": [
                        {"type": "text", "text": prompt},
                        {
                            "type": "image_url",
                            "image_url": {
                                "url": f"data:{mime_type};base64,{base64_image}",
                                "detail": detail,
                            },
                        },
                    ],
                }
            ],
            max_tokens=1000,
        )

        content = response.choices[0].message.content

        try:
            parsed = json.loads(content)
        except json.JSONDecodeError:
            parsed = {
                "description": content,
                "objects": [],
                "text": None,
                "colors": [],
                "confidence": 0.8,
            }

        parsed["model"] = response.model
        return parsed

    def _analyze_anthropic(self, image_path: str, prompt: str) -> Dict[str, Any]:
        """Analyze using Anthropic Claude."""
        base64_image = self.encode_image(image_path)
        suffix = Path(image_path).suffix.lower()
        media_type = {".jpg": "image/jpeg", ".jpeg": "image/jpeg", ".png": "image/png"}.get(
            suffix, "image/jpeg"
        )

        response = self.client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1000,
            messages=[
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "image",
                            "source": {
                                "type": "base64",
                                "media_type": media_type,
                                "data": base64_image,
                            },
                        },
                        {"type": "text", "text": prompt},
                    ],
                }
            ],
        )

        return {
            "description": response.content[0].text,
            "objects": [],
            "text": None,
            "colors": [],
            "confidence": 0.85,
            "model": response.model,
        }

    def batch_analyze(
        self, image_paths: List[str], prompt: str = "Describe this image"
    ) -> List[ImageAnalysis]:
        """Analyze multiple images."""
        results = []
        for path in image_paths:
            if Path(path).exists():
                result = self.analyze_image(path, prompt)
                results.append(result)
            else:
                print(f"Skipping {path} - file not found")
        return results

    def compare_images(
        self, image_paths: List[str], question: str
    ) -> Dict[str, Any]:
        """Compare multiple images and answer a question."""
        if self.provider != "openai":
            raise ValueError("Image comparison requires OpenAI provider")

        content = [{"type": "text", "text": question}]

        for path in image_paths:
            if Path(path).exists():
                base64_img = self.encode_image(path)
                suffix = Path(path).suffix.lower()
                mime = {".jpg": "image/jpeg", ".png": "image/png"}.get(
                    suffix, "image/jpeg"
                )
                content.append({
                    "type": "image_url",
                    "image_url": {
                        "url": f"data:{mime};base64,{base64_img}",
                        "detail": "high",
                    },
                })

        response = self.client.chat.completions.create(
            model="gpt-4o",
            messages=[{"role": "user", "content": content}],
            max_tokens=1000,
        )

        return {
            "question": question,
            "images_analyzed": len(image_paths),
            "response": response.choices[0].message.content,
            "model": response.model,
        }

    @staticmethod
    def generate_report(analyses: List[ImageAnalysis]) -> str:
        """Generate a summary report of all analyses."""
        report = [
            "=" * 60,
            "MULTIMODAL IMAGE ANALYSIS REPORT",
            "=" * 60,
            f"\nTotal images analyzed: {len(analyses)}",
            f"Average processing time: {sum(a.processing_time_ms for a in analyses) / len(analyses):.0f}ms",
            f"Model used: {analyses[0].model_used if analyses else 'N/A'}",
            "\n" + "-" * 40,
        ]

        for i, analysis in enumerate(analyses, 1):
            report.append(f"\n{i}. {analysis.image_path}")
            report.append(f"   Description: {analysis.description[:100]}...")
            if analysis.objects_detected:
                report.append(f"   Objects: {', '.join(analysis.objects_detected[:5])}")
            if analysis.text_extracted:
                report.append(f"   Text found: {analysis.text_extracted[:50]}...")
            report.append(f"   Processing time: {analysis.processing_time_ms:.0f}ms")

        return "\n".join(report)


